// ============================================================
// FUNCTION NODE: discovery-mock
// Eingang:  inject "boot"
// Ausgang:  -> schema-loader
// ------------------------------------------------------------
// PoC: Hardware fest verdrahtet.
// Spaeter durch echten I2C-Scan / EEPROM-Read ersetzen.
// Nur DIESE Node tauschen, der Rest bleibt unveraendert.
// SO
// ============================================================

msg.discovery = [
    { slot: 1, type: "relay" },
    { slot: 2, type: "current" },
    { slot: 3, type: "demo"}
];

return msg;

// ============================================================
// FUNCTION NODE: schema-loader
// Eingang:  action-registry
// Ausgang:  -> instance-builder
// ------------------------------------------------------------
// PoC: Karten-Schemas inline.
// Spaeter: per WebSocket vom Backend empfangen.
// Registry und Actions sind in separaten Nodes.
// ============================================================

// ---- Karten-Schemas ----------------------------------------
flow.set("schemas", {
    relay: {
        cardType: "relay",
        displayName: "Relaiskarte",
        version: "1.0",
        io: { channels: 4, protocol: "i2c" },
        views: {
            user: {
                groups: [
                    {
                        title: "Relais",
                        elements: [
                            { id: "relay", type: "toggle", label: "Relais {ch}",
                              repeat: "channels", rw: "write",
                              onChange: "writeRelay", commit: "immediate" }
                        ]
                    },
                    {
                        title: "default state",
                        elements: [
                            { id: "state", type: "toggle", label: "Default state Relais {ch}", repeat: "channels", rw: "write"}
                        ]
                    },
                    {
                        title: "Steuerung",
                        elements: [
                            { id: "log_start", type: "button", label: "Log starten",
                              onClick: "startLog" }
                        ]
                    }
                ]
            },
            config: {
                groups: [
                    {
                        title: "Kanal-Setup",
                        elements: [
                            { id: "mode", type: "dropdown", label: "Modus {ch}",
                              repeat: "channels", options: ["NO", "NC"], default: "NO",
                              onChange: "setMode", commit: "onSave" },
                            { id: "debounce", type: "numeric", label: "Entprellzeit {ch} (ms)",
                              repeat: "channels", min: 0, max: 1000, default: 50,
                              onChange: "setDebounce", commit: "onSave" }
                        ]
                    }
                ]
            }
        }
    },
    current: {
        cardType: "current",
        displayName: "Strommesskarte",
        version: "1.0",
        io: { channels: 2, protocol: "i2c" },
        views: {
            user: {
                groups: [
                    {
                        title: "Messwerte",
                        elements: [
                            { id: "current", type: "output", label: "Strom {ch} (A)",
                              repeat: "channels", rw: "read", onChange: "readCurrent" }
                        ]
                    }
                ]
            },
            config: {
                groups: [
                    {
                        title: "Messbereich",
                        elements: [
                            { id: "range", type: "dropdown", label: "Bereich {ch}",
                              repeat: "channels", options: ["1A", "10A", "50A"], default: "10A",
                              onChange: "setRange", commit: "onSave" },
                            { id: "samplerate", type: "numeric", label: "Samplerate {ch} (Hz)",
                              repeat: "channels", min: 1, max: 1000, default: 100,
                              onChange: "setSampleRate", commit: "onSave" }
                        ]
                    }
                ]
            }
        }
    },
    demo: {
        cardType: "demo",
        displayName: "Demo-Karte (alle Elemente)",
        version: "1.0",
        io: { channels: 3, protocol: "i2c" },
        views: {
            user: {
                groups: [
                    {
                        title: "toggle \u2014 Ein/Aus-Schalter",
                        elements: [
                            { id: "power", type: "toggle", label: "Hauptschalter",
                              onChange: "demoWrite", commit: "immediate" },
                            { id: "relay", type: "toggle", label: "Kanal {ch}",
                              repeat: "channels", onChange: "demoWrite", commit: "immediate" }
                        ]
                    },
                    {
                        title: "button \u2014 Aktion ausloesen",
                        elements: [
                            { id: "start", type: "button", label: "Start", onClick: "demoAction" },
                            { id: "stop",  type: "button", label: "Stopp", onClick: "demoAction" }
                        ]
                    },
                    {
                        title: "output \u2014 Nur-Lese-Anzeige (Messwerte)",
                        elements: [
                            { id: "value", type: "output", label: "Messwert {ch}",
                              repeat: "channels", rw: "read", onChange: "demoRead" }
                        ]
                    },
                    {
                        title: "led / badge / status-panel \u2014 komplexe Elemente",
                        elements: [
                            { id: "fb",       type: "led",          label: "R\u00fcckm. {ch}",
                              repeat: "channels", rw: "read", onChange: "demoRead" },
                            { id: "status",   type: "badge",        label: "Systemstatus",
                              rw: "read", onChange: "demoRead" },
                            { id: "overview", type: "status-panel", label: "\u00dcbersicht",
                              ledCount: 4,
                              buttons: [
                                  { id: "reset", label: "Reset", action: "demoAction" },
                                  { id: "test",  label: "Test",  action: "demoAction" }
                              ]
                            }
                        ]
                    }
                ]
            },
            config: {
                groups: [
                    {
                        title: "numeric \u2014 Zahleneingabe mit Grenzen",
                        elements: [
                            { id: "threshold", type: "numeric", label: "Schwellwert (global)",
                              min: 0, max: 100, step: 1, default: 50,
                              onChange: "demoConfig", commit: "onSave" },
                            { id: "delay", type: "numeric", label: "Verzoegerung {ch} (ms)",
                              repeat: "channels", min: 0, max: 5000, step: 10, default: 100,
                              onChange: "demoConfig", commit: "onSave" }
                        ]
                    },
                    {
                        title: "dropdown \u2014 Auswahl aus festen Optionen",
                        elements: [
                            { id: "mode", type: "dropdown", label: "Betriebsmodus",
                              options: ["Auto", "Manuell", "Aus"], default: "Auto",
                              onChange: "demoConfig", commit: "onSave" },
                            { id: "range", type: "dropdown", label: "Bereich {ch}",
                              repeat: "channels", options: ["niedrig", "mittel", "hoch"], default: "mittel",
                              onChange: "demoConfig", commit: "onSave" }
                        ]
                    },
                    {
                        title: "Gemischt \u2014 immediate vs. onSave in einer Gruppe",
                        elements: [
                            { id: "live_offset", type: "numeric", label: "Live-Offset (sofort)",
                              min: -50, max: 50, default: 0,
                              onChange: "demoConfig", commit: "immediate" },
                            { id: "saved_gain", type: "numeric", label: "Verstaerkung (erst speichern)",
                              min: 1, max: 10, default: 1,
                              onChange: "demoConfig", commit: "onSave" }
                        ]
                    }
                ]
            }
        }
    }

});

return msg;

// ============================================================
// FUNCTION NODE: instance-builder
// Eingang:  schema-loader
// Ausgang:  -> render-user  UND  render-config  (zwei Drähte
//              vom selben Ausgang, oder 2 Outputs - hier 1 Output,
//              beide Templates am selben Draht)
// ------------------------------------------------------------
// Kernlogik: Discovery + Schemas + Registry  ->  tabs[]
// - klont pro Slot das Schema
// - vergibt Slash-Topics im Projekt-Stil: slot1/relay/1 (kollisionsfrei)
// - expandiert repeat -> {ch}
// - merged Registry-Eintrag (component/cssClass/defaults/emits)
// - schreibt flow.instances (Meta fuer den Dispatcher, Key = Topic)
// ============================================================

const slots     = msg.discovery;
const schemas   = flow.get("schemas");
const registry  = flow.get("registry");
const tabs      = [];
const instances = {};

function expand(view, slot, prefix, io) {
    const groups = [];
    for (const g of view.groups) {
        const els = [];
        for (const el of g.elements) {
            const count = el.repeat === "channels" ? io.channels : 1;
            for (let ch = 1; ch <= count; ch++) {
                const reg = registry[el.type] || {};
                // Slash-Topic im Projekt-Stil (kompakt): slot1/relay/1
                const topic = el.repeat
                    ? prefix + "/" + el.id + "/" + ch
                    : prefix + "/" + el.id;

                els.push(Object.assign({}, el, {
                    topic:     topic,
                    label:     (el.label || "").replace("{ch}", ch),
                    component: reg.component,
                    template:  reg.template || null,
                    cssClass:  reg.cssClass,
                    emits:     reg.emits,
                    defaults:  reg.defaults || {},
                    value:     el.default !== undefined ? el.default : null
                }));

                instances[topic] = {
                    slot:   slot,
                    addr:   topic,                    // PoC: Topic == Adresse
                    action: el.onChange || el.onClick || null,
                    commit: el.commit || "immediate"
                };

                // Status-Panel: Button-Sub-Topics im instances-Register eintragen
                for (const btn of el.buttons || []) {
                    instances[topic + "/" + btn.id] = {
                        slot:   slot,
                        addr:   topic + "/" + btn.id,
                        action: btn.action,
                        commit: "immediate"
                    };
                }
            }
        }
        groups.push({ title: g.title, elements: els });
    }
    return { groups: groups };
}

for (const s of slots) {
    const schema = JSON.parse(JSON.stringify(schemas[s.type]));
    const tabId  = "slot" + s.slot + "_" + s.type;   // interne Tab-ID (kein Topic)
    const prefix = "slot" + s.slot;                  // Topic-Praefix: slot1/...
    tabs.push({
        tabId: tabId,
        title: schema.displayName + " (Slot " + s.slot + ")",
        user:   expand(schema.views.user,   s.slot, prefix, schema.io),
        config: expand(schema.views.config, s.slot, prefix, schema.io)
    });
}

flow.set("instances", instances);
msg.payload = tabs;
return msg;

// ============================================================
// FUNCTION NODE: dispatcher
// Eingang:  render-user / render-config (Element-Events)
// Ausgang:  -> switch "target"
// ------------------------------------------------------------
// Projekt-Konvention: msg.topic = Adresse, msg.payload = Wert.
// commit-Steuerung: "immediate" schreibt sofort,
//                   "onSave" puffert bis msg.forceCommit.
// ============================================================

const topic   = msg.topic;                         // z.B. "slot1/relay/1"
const value   = msg.payload;                       // reiner Wert
const meta    = (flow.get("instances") || {})[topic];
const actions = flow.get("actions") || {};

if (!meta) {
    node.warn("Unbekanntes Topic: " + topic);
    return null;
}

// onSave: puffern statt sofort schreiben
if (meta.commit === "onSave" && !msg.forceCommit) {
    const buf = flow.get("pending") || {};
    buf[topic] = value;
    flow.set("pending", buf);
    node.status({ fill: "yellow", shape: "ring", text: "gepuffert: " + topic });
    return null;
}

const fn = actions[meta.action];
if (!fn) {
    node.warn("Unbekannte Aktion: " + meta.action);
    return null;
}

// Ergebnis: msg.topic bleibt erhalten, msg.payload = Kommando-Objekt
msg.payload = fn({
    topic: topic,
    value: value,
    slot:  meta.slot,
    addr:  meta.addr
});

return msg;

// ============================================================
// FUNCTION NODE: io-sim
// Eingang:  switch "target" (Ausgang 1: io)
// Ausgang:  -> debug "out"
// ------------------------------------------------------------
// Simuliert Hardware-Zugriff.
// Spaeter: durch node-red-contrib-i2c ersetzen,
//          addr aus instanceKey auf echte Register mappen.
// ============================================================

const p = msg.payload;
const store = flow.get("io_state") || {};

if (p.op === "write" || p.op === "config") {
    const k = p.addr + (p.field ? ":" + p.field : "");
    store[k] = p.value;
    flow.set("io_state", store);
    node.warn("IO " + p.op + " -> " + p.addr + (p.field ? ("." + p.field) : "") + " = " + p.value);

} else if (p.op === "read") {
    const val = (Math.random() * 10).toFixed(2);   // Fake-Messwert
    node.warn("IO read <- " + p.addr + " = " + val + " A");
    msg.payload = { addr: p.addr, value: val };
}

return msg;

// ============================================================
// FUNCTION NODE: logger-sim
// Eingang:  switch "target" (Ausgang 2: logger)
// Ausgang:  -> debug "out"
// ------------------------------------------------------------
// Simuliert den Logger-Start.
// Spaeter: echtes Logging / File-Write anbinden.
// ============================================================

node.warn("LOGGER " + msg.payload.op + " (Slot " + msg.payload.slot + ")");

return msg;

format:
/* ============================================================
   theme-styles
   NUR Variablen-Definitionen — kein strukturelles CSS hier.
   Wer den Style aendern will, aendert NUR diese Datei.
   Alle Variablen die hier stehen werden in elements-styles benutzt.
   ============================================================ */

:root {
  /* === Basis-Farben (Drive Net Lab Corporate Design) === */
  --color-accent:      #13a538;   /* Velocity Green */
  --color-accent-2:    #afcb37;   /* Volt Lime */
  --color-warning:     #ec6726;   /* Ignition Orange */
  --color-bg:          #012229;   /* Asphalt Teal */
  --color-surface:     #0a2f37;
  --color-border:      #1c4651;
  --color-text:        #eaf3ee;
  --color-text-muted:  #8fb3ad;

  /* === Geometrie === */
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 16px;

  /* === Abstände === */
  --spacing-xs: 2px;
  --spacing-sm: 6px;
  --spacing-md: 12px;
  --spacing-lg: 20px;

  /* === Layout-Tokens === */
  --layout-padding:    var(--spacing-md);
  --layout-group-gap:  var(--spacing-md);
  --layout-title-size: 0.85rem;
  --el-spacing:        var(--spacing-sm);

  /* === el-toggle === */
  --el-toggle-color: var(--color-accent);

  /* === el-button === */
  --el-button-bg:     var(--color-accent);
  --el-button-text:   var(--color-bg);
  --el-button-radius: var(--radius-sm);
  --el-button-glow:   rgba(19, 165, 56, 0.40);

  /* === el-fields (numeric, dropdown, output) === */
  --el-field-border:  var(--color-border);
  --el-field-radius:  var(--radius-sm);
  --el-output-bg:     rgba(0, 0, 0, 0.25);

  /* === el-led === */
  --el-led-size:    10px;
  --el-led-spacing: 5px;
  --el-led-glow:    6px;
  --el-led-on:      var(--color-accent);
  --el-led-off:     #1a3a40;

  /* === el-status-panel === */
  --el-panel-border:  var(--color-border);
  --el-panel-radius:  var(--radius-md);
  --el-panel-padding: var(--spacing-md);
  --el-panel-bg:      rgba(255, 255, 255, 0.03);
}

/* ============================================================
   elements-styles
   Strukturelles CSS fuer alle Element-Typen.
   KEINE hartkodierten Farben oder Radii — nur var(--...).
   Tokens kommen ausschliesslich aus theme-styles.
   ! Das ist ein Test !
   ============================================================ */

/* ===== Layout ===== */
.poc-root {
  background: var(--color-bg);
  color: var(--color-text);
  font-family: "Magistral", "Roboto", system-ui, sans-serif;
  padding: var(--layout-padding);
}
.poc-group {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  padding: var(--layout-padding);
  margin-bottom: var(--layout-group-gap);
}
.poc-group-title {
  color: var(--color-text);
  font-size: var(--layout-title-size);
  letter-spacing: 0.04em;
  text-transform: uppercase;
  margin: 0 0 var(--spacing-sm) 0;
  padding-bottom: var(--spacing-xs);
  border-bottom: 1px solid var(--color-border);
}
.poc-el {
  display: flex;
  align-items: center;
  gap: var(--el-spacing);
  padding: var(--spacing-xs) 0;
}

/* ===== el-toggle ===== */
.el-toggle {
  accent-color: var(--el-toggle-color);
}

/* ===== el-button ===== */
.el-button {
  background-color: var(--el-button-bg) !important;
  color: var(--el-button-text) !important;
  border-radius: var(--el-button-radius) !important;
  box-shadow: 0 0 8px var(--el-button-glow) !important;
  font-weight: 600;
}

/* ===== el-numeric / el-dropdown / el-output ===== */
.el-numeric .v-field__outline,
.el-dropdown .v-field__outline {
  border-color: var(--el-field-border) !important;
  border-radius: var(--el-field-radius) !important;
}
.el-output {
  background: var(--el-output-bg);
  border-radius: var(--el-field-radius);
}

/* ===== el-led ===== */
.el-led {
  display: inline-block;
  width: var(--el-led-size);
  height: var(--el-led-size);
  border-radius: 50%;
  background: var(--el-led-off);
  transition: background 0.15s, box-shadow 0.15s;
  flex-shrink: 0;
}
.el-led--on {
  background: var(--el-led-on);
  box-shadow: 0 0 var(--el-led-glow) var(--el-led-on);
}

/* ===== el-status-panel ===== */
.el-status-panel {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
  border: 1px solid var(--el-panel-border);
  border-radius: var(--el-panel-radius);
  padding: var(--el-panel-padding);
  background: var(--el-panel-bg);
  width: 100%;
}
.el-status-panel__label {
  font-size: var(--layout-title-size);
  color: var(--color-text-muted);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}
.el-status-panel__leds {
  display: flex;
  gap: var(--el-led-spacing);
  align-items: center;
}
.el-status-panel__output {
  font-family: monospace;
  font-size: 0.9rem;
  color: var(--color-text);
  background: var(--el-output-bg);
  border-radius: var(--el-field-radius);
  padding: 2px 8px;
  min-height: 1.6em;
}
.el-status-panel__buttons {
  display: flex;
  gap: var(--spacing-sm);
  flex-wrap: wrap;
}

/* ===== el-badge ===== */
.el-badge {
  display: inline-block;
  padding: 1px var(--spacing-sm);
  border-radius: var(--radius-sm);
  font-size: 0.8rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  background: var(--el-badge-bg);
  color: var(--el-badge-text);
}
.el-badge--ok      { --el-badge-bg: var(--el-badge-ok-bg);   --el-badge-text: var(--el-badge-ok-text); }
.el-badge--warn    { --el-badge-bg: var(--el-badge-warn-bg);  --el-badge-text: var(--el-badge-warn-text); }
.el-badge--err     { --el-badge-bg: var(--el-badge-err-bg);   --el-badge-text: var(--el-badge-err-text); }
.el-badge--unknown { --el-badge-bg: var(--el-badge-off-bg);   --el-badge-text: var(--color-text-muted); }

func:
// ============================================================
// FUNCTION NODE: element-registry
// Eingang:  discovery-mock
// Ausgang:  -> action-registry
// ------------------------------------------------------------
// Definiert die Element-Registry: Typ → Vuetify-Komponente,
// CSS-Klasse, Defaults und Event-Name.
// Komplexe Typen (led, badge, status-panel) haben component: null
// und stattdessen einen template-Key für den Render-Switch.
// ============================================================

flow.set("registry", {
    toggle:   { component: "v-switch",     cssClass: "el-toggle",
                defaults: { color: "var(--accent)", inset: true, hideDetails: true },
                emits: "update:modelValue" },
    button:   { component: "v-btn",        cssClass: "el-button",
                defaults: { variant: "flat" },
                emits: "click" },
    numeric:  { component: "v-text-field", cssClass: "el-numeric",
                defaults: { type: "number", variant: "outlined", density: "compact", hideDetails: true },
                emits: "update:modelValue" },
    dropdown: { component: "v-select",     cssClass: "el-dropdown",
                defaults: { variant: "outlined", density: "compact", hideDetails: true },
                emits: "update:modelValue" },
    output:   { component: "v-text-field", cssClass: "el-output",
                defaults: { readonly: true, variant: "plain", density: "compact", hideDetails: true },
                emits: "update:modelValue" },
    led:            { component: null, template: "led",          cssClass: "el-led",          emits: null, defaults: {} },
    badge:          { component: null, template: "badge",        cssClass: "el-badge",        emits: null, defaults: {} },
    "status-panel": { component: null, template: "status-panel", cssClass: "el-status-panel", emits: null, defaults: {} }
});

return msg;

// ============================================================
// FUNCTION NODE: action-registry
// Eingang:  element-registry
// Ausgang:  -> schema-loader
// ------------------------------------------------------------
// Definiert alle Actions: Name → Funktion(context) → Command.
// context = { topic, value, slot, addr }
// Command = { target, op, ... } → wird vom Dispatcher geroutet.
// ============================================================

flow.set("actions", {
    writeRelay:    function (c) { return { target: "io",     op: "write",  addr: c.addr, value: c.value }; },
    setMode:       function (c) { return { target: "io",     op: "config", addr: c.addr, field: "mode",       value: c.value }; },
    setDebounce:   function (c) { return { target: "io",     op: "config", addr: c.addr, field: "debounce",   value: c.value }; },
    setRange:      function (c) { return { target: "io",     op: "config", addr: c.addr, field: "range",      value: c.value }; },
    setSampleRate: function (c) { return { target: "io",     op: "config", addr: c.addr, field: "samplerate", value: c.value }; },
    readCurrent:   function (c) { return { target: "io",     op: "read",   addr: c.addr }; },
    startLog:      function (c) { return { target: "logger", op: "start",  slot: c.slot }; },

    // ---- Demo-Karte ----
    demoWrite:     function (c) { return { target: "io",     op: "write",  addr: c.addr, value: c.value }; },
    demoConfig:    function (c) { return { target: "io",     op: "config", addr: c.addr, value: c.value }; },
    demoRead:      function (c) { return { target: "io",     op: "read",   addr: c.addr }; },
    demoAction:    function (c) { return { target: "logger", op: "action", addr: c.addr }; }
});

return msg;
